const _buildWinnersPayload = () => {
  if (!activeTournament.value || !activeTournament.value.winners) return null;
  const winners = activeTournament.value.winners;
  const pList = activeTournament.value.players || [];
  const getPlayerDetails = (id, rankIdx) => {
