  // For PDF: use Ctrl+P → Save as PDF hint; for image: use html2canvas approach
  const scriptBlock = isPDF
    ? `<script>
        document.title = 'بطولة ${tournamentName.replace(/'/g, "\\'")} - ${loungeName.replace(/'/g, "\\'")} - تقرير رسمي';
        window.onload = () => { window.print(); };
